import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import { Plus, Search, Users, Bell, FileText, ClipboardCheck, Heart, Shield, Clock } from "lucide-react";

const SecretaryPortal = () => {
  const [students, setStudents] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [studentDialogOpen, setStudentDialogOpen] = useState(false);
  const [announcementDialogOpen, setAnnouncementDialogOpen] = useState(false);

  const user = authService.getUser();

  const kenyaClasses = [
    "PP1","PP2","Grade 1","Grade 2","Grade 3","Grade 4","Grade 5","Grade 6",
    "Grade 7","Grade 8","Grade 9","Grade 10","Grade 11","Grade 12"
  ];

  const [studentForm, setStudentForm] = useState({
    admission_number: "",
    full_name: "",
    date_of_birth: "",
    gender: "male",
    class_name: "",
    stream: "",
    guardian_name: "",
    guardian_phone: "",
    guardian_email: "",
    guardian_relationship: "parent"
  });

  const [announcementForm, setAnnouncementForm] = useState({
    title: "",
    content: "",
    target_audience: "all",
    target_class: "",
    priority: "normal"
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [studentsRes, announcementsRes] = await Promise.all([
        apiClient.get("/students?approval_status=all"),
        apiClient.get("/announcements?approval_status=all"),
      ]);

      setStudents(studentsRes.data || []);
      setAnnouncements(announcementsRes.data || []);
    } catch (error) {
      toast.error("Failed to load portal data");
    } finally {
      setLoading(false);
    }
  };

  const approvalColor = (status) => {
    if (status === "approved") return "bg-green-100 text-green-800";
    if (status === "rejected") return "bg-red-100 text-red-800";
    return "bg-yellow-100 text-yellow-800";
  };

  const filteredStudents = (students || []).filter(s =>
    s?.full_name?.toLowerCase().includes(search.toLowerCase()) ||
    s?.admission_number?.toLowerCase().includes(search.toLowerCase())
  );

  const pendingStudents = (students || []).filter(s => s?.approval_status === "pending").length;
  const approvedStudents = (students || []).filter(s => s?.approval_status === "approved").length;

  const handleSubmitStudent = async (e) => {
    e.preventDefault();
    try {
      const res = await apiClient.post("/students", studentForm);

      toast.success(
        res?.data?.approval_status === "pending"
          ? "Sent for admin approval"
          : "Student added"
      );

      setStudentDialogOpen(false);
      fetchData();
    } catch (err) {
      toast.error(err?.response?.data?.detail || "Failed to create student");
    }
  };

  const handleSubmitAnnouncement = async (e) => {
    e.preventDefault();
    try {
      const res = await apiClient.post("/announcements", announcementForm);

      toast.success(
        res?.data?.approval_status === "pending"
          ? "Sent for approval"
          : "Posted"
      );

      setAnnouncementDialogOpen(false);
      fetchData();
    } catch (err) {
      toast.error(err?.response?.data?.detail || "Failed to post announcement");
    }
  };

  return (
    <div className="space-y-6">
      {/* HEADER */}
      <div className="bg-gradient-to-r from-amber-600/20 to-orange-600/20 border border-amber-500/20 rounded-2xl p-8">
        <h2 className="text-4xl font-bold text-white">Secretary Portal</h2>
        <p className="text-amber-300/70 mt-2">Welcome, {user?.full_name}</p>
      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card><CardContent className="p-4">
          <p className="text-slate-400">Total Students</p>
          <p className="text-2xl text-white">{students?.length || 0}</p>
        </CardContent></Card>

        <Card><CardContent className="p-4">
          <p className="text-slate-400">Approved</p>
          <p className="text-2xl text-green-400">{approvedStudents}</p>
        </CardContent></Card>

        <Card><CardContent className="p-4">
          <p className="text-slate-400">Pending</p>
          <p className="text-2xl text-yellow-400">{pendingStudents}</p>
        </CardContent></Card>
      </div>

      {/* STUDENTS TABLE */}
      <Card>
        <CardHeader>
          <CardTitle>Students</CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <p>Loading...</p>
          ) : filteredStudents.length === 0 ? (
            <p className="text-slate-400">No students found</p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Name</TableHead>
                  <TableHead>Class</TableHead>
                  <TableHead>Guardian</TableHead>
                  <TableHead>Status</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredStudents.map(s => (
                  <TableRow key={s.id}>
                    <TableCell>{s.full_name}</TableCell>
                    <TableCell>{s.class_name}</TableCell>
                    <TableCell>{s.guardian_name}</TableCell>
                    <TableCell>
                      <Badge className={approvalColor(s.approval_status)}>
                        {s.approval_status}
                      </Badge>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default SecretaryPortal;
